                    }
                    else if (className == DynamoDBRangeKeyAttr)
                    {
                        isRangeKey = true;
                        var customName = GetAttributeNameArg(attr);
                        if (customName != null)
                        {
                            attrName = customName;
                        }
                    }
                    else if (className == DynamoDBPropertyAttr)
                    {
