            // Check named arguments (AttributeName = "...")
            foreach (var named in attr.NamedArguments)
            {
                if (named.Key == "AttributeName" && named.Value.Value is string s && !string.IsNullOrWhiteSpace(s))
                {
                    return s;
                }
            }

            return null;
        }

