                .Where(t => !string.IsNullOrEmpty(t.Namespace))
                .Select(t => t.Namespace)
                .Distinct()
                .OrderBy(n => n);
            foreach (var ns in namespaces)
            {
                sb.AppendLine($"using {ns};");
            }
            sb.AppendLine();

            sb.AppendLine("namespace DynamoDBv2.Transactions.Generated");
            sb.AppendLine("{");
            sb.AppendLine("    internal static class DynamoDbMappingRegistration");
            sb.AppendLine("    {");
            sb.AppendLine("        [ModuleInitializer]");
            sb.AppendLine("        internal static void Register()");
            sb.AppendLine("        {");

            foreach (var type in types)
            {
                var typeName = string.IsNullOrEmpty(type.Namespace)
                    ? type.Name
                    : $"{type.Namespace}.{type.Name}";

                sb.AppendLine($"            DynamoDbMapper.RegisterGeneratedMapping<{typeName}>(");
                sb.AppendLine($"                new GeneratedTypeMapping<{typeName}>(");
                sb.AppendLine($"                    {typeName}.__DynamoDbMetadata.TableName,");
                sb.AppendLine($"                    {typeName}.__DynamoDbMetadata.HashKeyAttributeName,");
                sb.AppendLine($"                    {typeName}.__DynamoDbMetadata.GetPropertyAttributeName,");
                sb.AppendLine($"                    obj => {typeName}.__DynamoDbMetadata.MapToAttributes(obj),");
                sb.AppendLine($"                    item => {typeName}.__DynamoDbMetadata.GetVersion(item)));");
            }

            sb.AppendLine("        }");
            sb.AppendLine("    }");
            sb.AppendLine("}");

            return sb.ToString();
